  `id` int NOT NULL AUTO_INCREMENT,
  `politician_id` int NOT NULL,
  `relative_name` varchar(200) COLLATE utf8mb4_general_ci NOT NULL,
  `relative_role` varchar(200) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `relationship` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `institution` varchar(200) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `evidence` text COLLATE utf8mb4_general_ci,
  `source_url` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `source_title` varchar(300) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `confidence` enum('alta','media','baixa') COLLATE utf8mb4_general_ci DEFAULT 'media',
  `status` enum('confirmado','suspeita','descartado') COLLATE utf8mb4_general_ci DEFAULT 'suspeita',
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `politician_id` (`politician_id`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

