INSERT INTO `nepotism_alerts` (`id`, `politician_id`, `relative_name`, `relative_role`, `relationship`, `institution`, `evidence`, `source_url`, `source_title`, `confidence`, `status`, `created_at`, `updated_at`) VALUES
(5, 78, 'Igor Abreu', 'Secretário de Estado da Regularização Fundiária', 'irmão', 'Governo do Estado do Tocantins', 'Igor Abreu, filho de Kátia Abreu e irmão do senador Irajá Abreu, foi nomeado secretário de Estado da Regularização Fundiária no governo de Eduardo Leite no Tocantins. A nomeação ocorreu durante o mandato atual do senador Irajá Abreu (2023-2026) e foi amplamente criticada por movimentos sociais.', 'https://news.google.?oc=5', 'Criticado por movimentos sociais, filho de Kátia Abreu assume secretaria de regularização fundiária no Tocantins - Repórter Brasil', 'alta', 'confirmado', '2026-03-31 01:34:42', '2026-03-31 01:34:42'),
(6, 80, 'Não especificado', 'Secretário', 'outro', 'Governo do Tocantins', 'O governador Wagner exonerou um secretário que havia sido indicado por Alexandre Guimarães, conforme notícia de 2024. A notícia menciona a exoneração de um secretário indicado por Alexandre Guimarães, mas não fornece o nome do indicado nem o grau de parentesco.', 'https://news.google.?oc=5', 'Wagner exonera secretário indicado por Alexandre Guimarães e gera especulações políticas - afnoticias.com.br', 'baixa', 'suspeita', '2026-03-31 01:35:11', '2026-03-31 01:35:11'),
(7, 87, 'Marlei Ribeiro', 'cargo comissionado', 'outro', 'gestão municipal de Palmas', 'Notícia menciona que Marlei Ribeiro entregou cargo na gestão de Palmas como parte do grupo de Vicentinho Jr, indicando nomeação política', 'https://news.google.?oc=5', 'Grupo de Vicentinho Jr também entrega cargos na gestão de Palmas: “Não estou gostando do que estou vendo”, diz deputado; saíram Marlei Ribeiro e André Cavalari - Cleber Toledo', 'media', 'suspeita', '2026-03-31 01:36:32', '2026-03-31 01:36:32'),
(8, 87, 'André Cavalari', 'cargo comissionado', 'outro', 'gestão municipal de Palmas', 'Notícia menciona que André Cavalari entregou cargo na gestão de Palmas como parte do grupo de Vicentinho Jr, indicando nomeação política', 'https://news.google.?oc=5', 'Grupo de Vicentinho Jr também entrega cargos na gestão de Palmas: “Não estou gostando do que estou vendo”, diz deputado; saíram Marlei Ribeiro e André Cavalari - Cleber Toledo', 'media', 'suspeita', '2026-03-31 01:36:32', '2026-03-31 01:36:32');

