--
-- Estrutura para tabela `news`
--

DROP TABLE IF EXISTS `news`;
CREATE TABLE IF NOT EXISTS `news` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(255) COLLATE utf8mb4_general_ci NOT NULL,
  `summary` text COLLATE utf8mb4_general_ci,
  `content` longtext COLLATE utf8mb4_general_ci,
  `category` varchar(80) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `author_id` int DEFAULT NULL,
  `featured` tinyint(1) DEFAULT '0',
  `published` tinyint(1) DEFAULT '0',
  `cover_emoji` varchar(10) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `cover_color` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `published_at` datetime DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `cover_url` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `author_id` (`author_id`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Despejando dados para a tabela `news`
--

INSERT INTO `news` (`id`, `title`, `summary`, `content`, `category`, `author_id`, `featured`, `published`, `cover_emoji`, `cover_color`, `published_at`, `created_at`, `updated_at`, `cover_url`) VALUES
(1, 'Tocantins registra recorde de exportações no agronegócio em 2026', 'Estado ultrapassou a marca de R$ 12 bilhões em exportações agrícolas no primeiro trimestre, puxado pela soja e pecuária.', '<p>O Tocantins alcançou um marco histórico nas exportações do agronegócio. Segundo dados da Secretaria de Agricultura, o estado exportou R$ 12,3 bilhões apenas no primeiro trimestre de 2026.</p><p>A soja continua sendo o principal produto, representando 45% do total exportado, seguida pela carne bovina (28%) e milho (15%). Os principais destinos são China, União Europeia e países do Oriente Médio.</p><p>\"Esse resultado reflete o investimento em infraestrutura logística e a competitividade do produtor tocantinense\", afirmou o secretário de Agricultura.</p>', 'Economia', NULL, 1, 1, '📈', '#E8F5E9', '2026-03-28 00:00:00', '2026-03-30 03:17:12', '2026-03-30 03:25:10', 'https://images.unsplash.com/photo-1625246333195-78d9c38ad449?w=800&h=400&fit=crop'),
(2, 'Assembleia aprova lei de transparência digital para municípios', 'Nova legislação obriga todas as prefeituras do TO a publicarem gastos em tempo real em portal digital até 2027.', '<p>A Assembleia Legislativa do Tocantins aprovou por unanimidade o Projeto de Lei que obriga todos os 139 municípios do estado a manterem portais de transparência digital atualizados em tempo real.</p><p>A lei estabelece prazo de 18 meses para adequação e prevê penalidades para gestores que não cumprirem as exigências.</p>', 'Política', NULL, 0, 1, '🏛️', '#E3F2FD', '2026-03-27 00:00:00', '2026-03-30 03:17:12', '2026-03-30 03:25:10', 'https://images.unsplash.com/photo-1529107386315-e1a2ed48a620?w=800&h=400&fit=crop'),
(3, 'Hospital Regional de Araguaína atinge 45% de conclusão', 'Obra do maior hospital do norte do estado avança e deve ser entregue no segundo semestre de 2027.', '<p>As obras do Hospital Regional de Araguaína atingiram 45% de execução, segundo relatório da Secretaria de Infraestrutura. O hospital terá 300 leitos, centro cirúrgico de alta complexidade e UTI neonatal.</p><p>O investimento total é de R$ 280 milhões, com recursos federais e estaduais. A previsão de entrega é para o segundo semestre de 2027.</p>', 'Saúde', NULL, 0, 1, '🏥', '#FFEBEE', '2026-03-26 00:00:00', '2026-03-30 03:17:12', '2026-03-30 03:25:10', 'https://images.unsplash.com/photo-1587351021759-3e566b6af7cc?w=800&h=400&fit=crop'),
(4, 'Programa de energia solar já atende 120 escolas no Tocantins', 'Iniciativa do governo estadual reduz em 40% os custos de energia das escolas beneficiadas.', '<p>O Programa Tocantins Solar já instalou painéis fotovoltaicos em 120 escolas da rede estadual, superando a meta intermediária de 100 unidades. A economia média é de 40% na conta de energia.</p><p>O programa prevê atingir 200 escolas até o final de 2025, com investimento total de R$ 45 milhões.</p>', 'Educação', NULL, 0, 1, '☀️', '#FFF8E1', '2026-03-25 00:00:00', '2026-03-30 03:17:12', '2026-03-30 03:25:10', 'https://images.unsplash.com/photo-1509391366360-2e959784a276?w=800&h=400&fit=crop'),
(5, 'Palmas sobe 15 posições no ranking de cidades inteligentes', 'Capital tocantinense é destaque em digitalização de serviços públicos e mobilidade urbana sustentável.', '<p>Palmas subiu 15 posições no ranking Connected Smart Cities 2026, alcançando a 42ª posição entre as cidades brasileiras. Os destaques foram nas categorias de tecnologia e inovação, mobilidade e meio ambiente.</p><p>O programa de Wi-Fi gratuito em praças e a digitalização dos serviços municipais foram citados como diferenciais.</p>', 'Tecnologia', NULL, 0, 1, '🌆', '#E3F2FD', '2026-03-24 00:00:00', '2026-03-30 03:17:12', '2026-03-30 03:25:10', 'https://images.unsplash.com/photo-1480714378408-67cf0d13bc1b?w=800&h=400&fit=crop'),
(6, 'Operação do MP investiga desvios em licitações de Gurupi', 'Ministério Público apura irregularidades em contratos de pavimentação que somam R$ 18 milhões.', '<p>O Ministério Público do Tocantins deflagrou operação para investigar possíveis irregularidades em licitações de pavimentação na cidade de Gurupi. Os contratos sob investigação somam R$ 18 milhões.</p><p>Segundo o MP, há indícios de superfaturamento e direcionamento de licitações. Cinco servidores foram afastados preventivamente.</p>', 'Investigação', NULL, 0, 1, '🔍', '#FFEBEE', '2026-03-23 00:00:00', '2026-03-30 03:17:12', '2026-03-30 03:25:10', 'https://images.unsplash.com/photo-1589829545856-d10d557cf95f?w=800&h=400&fit=crop'),
(7, 'Tocantins terá primeiro parque tecnológico do Norte do Brasil', 'Investimento de R$ 150 milhões criará hub de inovação em Palmas com foco em agritech e govtech.', '<p>O governador anunciou a criação do primeiro parque tecnológico da região Norte, que será instalado em Palmas com investimento de R$ 150 milhões. O espaço terá foco em agritech, govtech e energias renováveis.</p>', 'Tecnologia', NULL, 0, 1, '🚀', '#E8F5E9', '2026-03-22 00:00:00', '2026-03-30 03:17:12', '2026-03-30 03:25:10', 'https://images.unsplash.com/photo-1497366216548-37526070297c?w=800&h=400&fit=crop'),
(8, 'Índice de desmatamento no Tocantins cai 22% em relação a 2025', 'Monitoramento por satélite mostra redução significativa, mas cerrado ainda enfrenta pressão do agronegócio.', '<p>Dados do INPE mostram que o desmatamento no Tocantins caiu 22% no primeiro trimestre de 2026 em comparação com o mesmo período de 2025. A área desmatada foi de 450 km², contra 577 km² no ano anterior.</p>', 'Meio Ambiente', NULL, 0, 1, '🌳', '#E8F5E9', '2026-03-21 00:00:00', '2026-03-30 03:17:12', '2026-03-30 03:25:10', 'https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=800&h=400&fit=crop');

